"use client";

import React from 'react';
import { Search } from 'lucide-react';

interface MobileSearchBarProps {
  searchTerm: string;
  setSearchTerm: (val: string) => void;
}

export default function MobileSearchBar({ searchTerm, setSearchTerm }: MobileSearchBarProps) {
  return (
    <div className="block md:hidden bg-[#121214] p-3.5 rounded-xl border border-[#232327]">
      <div className="relative">
        <span className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none text-zinc-550">
          <Search className="h-4 w-4" />
        </span>
        <input
          id="mobile-feed-search-input"
          type="text"
          placeholder="Search requirements (sofas, carpentry, tutoring...)"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full text-xs pl-9 pr-4 py-2.5 bg-[#0b0b0c] border border-[#2d2d34] text-zinc-100 rounded-lg placeholder-zinc-650 focus:outline-[#FF3F3F]/30 focus:border-[#FF3F3F]"
        />
      </div>
    </div>
  );
}
