"use client";

import { useState } from 'react';
import { Sparkles } from 'lucide-react';
import { Post, User } from '../types';

// Subcomponents inside/outside feed directory
import PostCard from './feed/PostCard';
import PostDetailModal from './feed/PostDetailModal';
import FeedSidebar from './feed/FeedSidebar';
import MobileSearchBar from './feed/MobileSearchBar';
import CategoryFilterRow from './feed/CategoryFilterRow';

interface HomeFeedProps {
  posts: Post[];
  currentUser: User;
  onAddComment: (
    postId: string, 
    commentContent: string, 
    isOffer: boolean, 
    offerBudget?: string, 
    offerDuration?: string,
    answers?: { question: string; answer: string }[]
  ) => void;
  onToggleResolve: (postId: string) => void;
  searchTerm: string;
  setSearchTerm: (val: string) => void;
  onInitiateChat: (participant: User) => void;
}

export default function HomeFeed({
  posts,
  currentUser,
  onAddComment,
  searchTerm,
  setSearchTerm,
  onInitiateChat
}: HomeFeedProps) {
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [focusedPostId, setFocusedPostId] = useState<string | null>(null);

  // Filtering Logic
  const filteredPosts = posts.filter(post => {
    // Search match
    const matchesSearch = 
      post.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      post.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
      post.author.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      post.category.toLowerCase().includes(searchTerm.toLowerCase());
      
    // Category match
    let matchesCategory = true;
    if (selectedCategory !== 'All') {
      if (selectedCategory === 'Urgent') {
        matchesCategory = post.title.toLowerCase().includes('sofa') || post.description.toLowerCase().includes('urgent');
      } else if (selectedCategory === 'Trending') {
        matchesCategory = post.offersCount >= 8;
      } else if (selectedCategory === 'Nearby') {
        matchesCategory = post.location.includes('Sector 62');
      } else if (selectedCategory === 'Premium') {
        matchesCategory = post.budget !== 'Negotiable';
      }
    }
    
    return matchesSearch && matchesCategory;
  });

  const focusedPost = posts.find(p => p.id === focusedPostId);

  return (
    <div className="space-y-6">
      {/* MOBILE-ONLY COMPACT SEARCH BAR (Modular) */}
      <MobileSearchBar searchTerm={searchTerm} setSearchTerm={setSearchTerm} />

      {/* FILTER BUTTONS ROW (Modular) */}
      <CategoryFilterRow 
        selectedCategory={selectedCategory} 
        setSelectedCategory={setSelectedCategory} 
        resultCount={filteredPosts.length} 
      />

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* LEFT COLUMN: Mini instructions & Stats */}
        <div className="lg:col-span-3 space-y-4 order-last lg:order-first">
          <FeedSidebar />
        </div>

        {/* MIDDLE/RIGHT COLUMN: Feed stream items */}
        <div className="lg:col-span-9 space-y-4 order-first lg:order-last">
          {filteredPosts.length === 0 ? (
            <div className="bg-[#121214] rounded-xl border border-[#232327] p-12 text-center select-none font-sans">
              <Sparkles className="w-10 h-10 text-zinc-650 mx-auto mb-3" />
              <p className="text-zinc-200 font-bold mb-1 font-display">No local matching requests found</p>
              <p className="text-xs text-zinc-500 max-w-sm mx-auto">
                No verified posts match your selection. Reset filters or create a custom requirement!
              </p>
            </div>
          ) : (
            filteredPosts.map(post => (
              <PostCard
                key={post.id}
                post={post}
                currentUser={currentUser}
                onSelect={() => setFocusedPostId(post.id)}
                onInitiateChat={onInitiateChat}
              />
            ))
          )}
        </div>
      </div>

      {/* DETAILED INTERACTIVE POPUP SHEET */}
      {focusedPost && (
        <PostDetailModal
          focusedPost={focusedPost}
          currentUser={currentUser}
          onClose={() => setFocusedPostId(null)}
          onAddComment={onAddComment}
        />
      )}
    </div>
  );
}
