"use client";

import React from 'react';
import { CATEGORIES } from '../../data';

interface CategoryFilterRowProps {
  selectedCategory: string;
  setSelectedCategory: (cat: string) => void;
  resultCount: number;
}

export default function CategoryFilterRow({
  selectedCategory,
  setSelectedCategory,
  resultCount
}: CategoryFilterRowProps) {
  return (
    <div className="flex items-center justify-between gap-4 flex-wrap bg-[#121214] p-3 rounded-xl border border-[#232327] font-sans select-none">
      <div className="flex flex-wrap gap-1.5 items-center">
        {CATEGORIES.map(category => (
          <button
            key={category}
            id={`cat-filter-${category.replace(/\s+/g, '-').toLowerCase()}`}
            onClick={() => setSelectedCategory(category)}
            className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all tracking-wide cursor-pointer uppercase ${
              selectedCategory === category 
                ? 'bg-[#FF3F3F] text-white shadow-md' 
                : 'bg-[#1e1e21] text-zinc-400 hover:text-white hover:bg-zinc-800'
            }`}
          >
            {category}
          </button>
        ))}
      </div>
      <div className="text-zinc-550 font-mono text-[10px] uppercase font-bold">
        {resultCount} Requirements Found
      </div>
    </div>
  );
}
